export function IcoHomeScreen() {
  const { palette } = useIlloStyle();
  const icons = [
    [48, 32], [100, 32], [152, 32],
    [48, 66], [100, 66], [152, 66],
    [48, 100], [100, 100], [152, 100],
  ];
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Phone outline */}
      <rect x="25" y="5" width="150" height="122" rx="12" fill="none" stroke={palette.mid} strokeWidth="2.5" />
      {/* App icons 3×3 */}
      {icons.map(([x, y], i) => (
        <rect key={i} x={x - 16} y={y - 12} width="32" height="24" rx="6"
          fill={i === 4 ? palette.accent : palette.mid}
          opacity={i === 4 ? 0.85 : 0.35} />
      ))}
      {/* Home bar */}
      <rect x="76" y="118" width="48" height="4" rx="2" fill={palette.mid} opacity="0.45" />
    </svg>
  );
}
